"""Frontend for the Edgewatch Network Operations Center."""

HTML_TEMPLATE = r"""<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Edgewatch NOC</title><script src="https://cdn.jsdelivr.net/npm/chart.js"></script><style>
:root{--bg:#0E1117;--card:#171B26;--panel:#121620;--line:rgba(255,255,255,.06);--accent:#7C83FF;--ok:#4CAF50;--warn:#F4B942;--bad:#E25A5A;--text:#F5F7FA;--muted:#9AA4B2}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:13px Inter,ui-sans-serif,system-ui,sans-serif}.side{position:fixed;inset:0 auto 0 0;width:224px;background:#12151d;border-right:1px solid var(--line);padding:18px 12px;display:flex;flex-direction:column}.brand{font-size:16px;font-weight:700;padding:10px 12px 26px}.logo{display:inline-grid;place-items:center;width:25px;height:25px;background:var(--accent);border-radius:7px;margin-right:8px}.nav a{display:block;color:var(--muted);text-decoration:none;padding:10px 12px;border-radius:7px;margin:3px 0}.nav a:hover,.nav a:first-child{background:#212644;color:var(--text)}.nav i{display:inline-block;width:25px;font-style:normal}.side small{margin-top:auto;padding:12px;color:var(--muted);line-height:1.6}.app{margin-left:224px}.top{height:64px;border-bottom:1px solid var(--line);display:flex;align-items:center;justify-content:space-between;padding:0 32px;position:sticky;top:0;background:rgba(14,17,23,.97);z-index:4}.crumb{font-weight:600}.top-right{display:flex;gap:12px;align-items:center;color:var(--muted)}.env,.sys{border:1px solid var(--line);padding:7px 9px;border-radius:7px;font-size:12px}.sys b{color:var(--ok)}main{padding:30px 38px 70px;max-width:1800px}.heading{display:flex;justify-content:space-between;align-items:end;margin-bottom:22px}.heading h1{font-size:27px;letter-spacing:-.045em;margin:0}.heading p{margin:7px 0 0;color:var(--muted)}.grid12{display:grid;grid-template-columns:repeat(12,minmax(0,1fr));gap:14px}.card{background:var(--card);border:1px solid var(--line);border-radius:12px;padding:18px;transition:transform .18s,border-color .18s}.card:hover{border-color:rgba(124,131,255,.3)}.kpi{grid-column:span 2;min-height:125px}.kpi.feature{background:#1d2231;border-color:rgba(124,131,255,.3)}.label{font-size:11px;color:var(--muted);text-transform:uppercase;letter-spacing:.07em}.value{font-size:25px;font-weight:650;letter-spacing:-.04em;margin:10px 0 7px}.delta{font-size:11px;color:var(--muted)}.delta b{color:var(--ok)}.spark{height:24px;width:100%;margin-top:10px}.section{margin-top:28px}.section-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}.section-head h2{font-size:15px;margin:0}.section-head span{color:var(--muted);font-size:12px}.topology{grid-column:span 8}.control{grid-column:span 4}.network{height:405px;width:100%;background:#11151f;border:1px solid var(--line);border-radius:9px}.n-label{fill:#dce1ea;font-size:12px}.n-meta{fill:#8f99aa;font-size:10px}.node{stroke:#11151f;stroke-width:5}.origin{fill:var(--warn)}.edge{fill:var(--accent)}.client{fill:#778194}.route{stroke:var(--ok);stroke-width:3;stroke-dasharray:8 8;animation:flow 1.5s linear infinite}.route.miss{stroke:var(--warn)}.route.fail{stroke:var(--bad)}@keyframes flow{to{stroke-dashoffset:-24}}.legend{color:var(--muted);font-size:11px;margin-top:10px}.legend i{display:inline-block;width:8px;height:8px;border-radius:50%;margin:0 5px 0 12px}.field{display:grid;gap:6px;margin-bottom:13px;color:var(--muted);font-size:12px}select,input{background:#11151f;border:1px solid var(--line);color:var(--text);padding:10px;border-radius:7px}.btn{border:0;border-radius:7px;background:var(--accent);color:white;padding:10px;width:100%;font-weight:650;cursor:pointer;transition:background .18s,transform .18s}.btn:hover{background:#9096ff}.btn:active{transform:translateY(1px)}.btn.secondary{background:#282e3d;margin-top:9px}.feed{margin-top:15px;height:180px;overflow:auto;background:#11151f;border:1px solid var(--line);padding:11px;border-radius:8px;color:var(--muted);font:11px ui-monospace,monospace;line-height:1.7}.charts .card{grid-column:span 4;min-height:260px}.charts .wide{grid-column:span 6}.charts canvas{max-height:225px}.health{grid-column:span 12}.health-row{display:grid;grid-template-columns:1.5fr repeat(5,1fr) 116px;gap:10px;align-items:center;padding:13px 0;border-bottom:1px solid var(--line)}.health-row:last-child{border:0}.healthy{color:var(--ok)}.critical{color:var(--bad)}.bar{height:5px;background:#292f3e;border-radius:8px;margin-top:5px}.bar i{display:block;height:100%;background:var(--accent);border-radius:inherit}.warn i{background:var(--warn)}.danger{background:rgba(226,90,90,.12);color:#f09696;border:1px solid rgba(226,90,90,.25)}.cache .card{grid-column:span 4}.file{display:flex;justify-content:space-between;padding:10px 0;border-bottom:1px solid var(--line);font:12px ui-monospace,monospace}.file span{color:var(--muted)}.tools{display:flex;gap:8px}.tools input{flex:1}.tools select,.tools button{width:auto}.table-wrap{overflow:auto;border:1px solid var(--line);border-radius:9px}table{width:100%;border-collapse:collapse}th{position:sticky;top:64px;background:#202633;color:var(--muted);font-size:11px;text-align:left;padding:11px}td{padding:12px 11px;border-top:1px solid var(--line)}tr:hover{background:rgba(255,255,255,.018)}.badge{padding:4px 7px;border-radius:99px;font-weight:650;font-size:11px}.hit{background:rgba(76,175,80,.14);color:#8fda95}.miss{background:rgba(244,185,66,.14);color:#f3ce79}.action{padding:5px 8px;border:1px solid var(--line);background:#252b39;color:var(--text);border-radius:5px;cursor:pointer}@media(max-width:1100px){.kpi{grid-column:span 4}.topology,.control,.charts .card,.charts .wide{grid-column:span 12}.cache .card{grid-column:span 6}}@media(max-width:720px){.side{position:static;width:auto;height:auto}.side small{display:none}.nav{display:flex;overflow:auto}.nav a{white-space:nowrap}.app{margin:0}.top{padding:0 16px}.top-right .env{display:none}main{padding:22px 16px}.kpi,.cache .card{grid-column:span 12}.health-row{grid-template-columns:1fr 1fr}.health-row .hide-mobile{display:none}}
</style></head><body><aside class="side"><div class="brand"><span class="logo">E</span>Edgewatch</div><nav class="nav"><a href="#overview"><i>◫</i>Overview</a><a href="#topology"><i>⌘</i>Topology</a><a href="#analytics"><i>◔</i>Analytics</a><a href="#requests"><i>☷</i>Requests</a><a href="#cache"><i>▣</i>Cache</a><a href="#health"><i>♥</i>Health</a><a href="#settings"><i>⚙</i>Settings</a></nav><small>EDGEWATCH NOC<br>Local simulation · v1.0</small></aside><div class="app"><header class="top"><div class="crumb">Operations / <span style="color:var(--muted)">CDN Platform</span></div><div class="top-right"><span class="env">Production simulation ▾</span><span class="sys"><b>●</b> All systems operational</span><span id="updated">Updated —</span></div></header><main><div class="heading"><div><h1>Network Operations Center</h1><p>Real-time edge routing, cache performance, and origin protection.</p></div><span class="label">LIVE TELEMETRY</span></div><section id="overview" class="grid12"><div class="card kpi feature"><div class="label">Total requests</div><div class="value" id="total">0</div><div class="delta" id="trend-total">No baseline</div><svg class="spark" id="spark-total"></svg></div><div class="card kpi"><div class="label">Cache hit rate</div><div class="value" id="rate">0%</div><div class="delta" id="trend-rate">No baseline</div><svg class="spark" id="spark-rate"></svg></div><div class="card kpi"><div class="label">Average latency</div><div class="value" id="latency">0 ms</div><div class="delta" id="trend-latency">No baseline</div><svg class="spark" id="spark-latency"></svg></div><div class="card kpi"><div class="label">Origin offload</div><div class="value" id="offload">0%</div><div class="delta">Cache-served request share</div><svg class="spark" id="spark-offload"></svg></div><div class="card kpi"><div class="label">Active edge nodes</div><div class="value" id="active">0/3</div><div class="delta">Routing-capable regions</div><svg class="spark" id="spark-active"></svg></div><div class="card kpi"><div class="label">Traffic volume</div><div class="value" id="traffic">0 B</div><div class="delta">Origin transfers avoided</div><svg class="spark" id="spark-traffic"></svg></div></section><section id="topology" class="section grid12"><div class="card topology"><div class="section-head"><h2>Live network graph</h2><span id="route-note">Awaiting route</span></div><svg class="network" viewBox="0 0 780 405"><g id="paths"></g><path d="M390 80V165 M210 235H570 M210 235L390 165 M570 235L390 165" stroke="#30394b" stroke-width="1.5"/><g><title>Mumbai Origin — primary content source</title><circle class="node origin" cx="390" cy="80" r="13"/><text class="n-label" x="411" y="78">Mumbai Origin</text><text class="n-meta" x="411" y="94">port 5000 · primary</text></g><g><title>Delhi regional edge</title><circle class="node edge" cx="210" cy="235" r="12"/><text class="n-label" x="136" y="262">Delhi Edge</text><text class="n-meta" x="136" y="277">port 5002</text></g><g><title>Bangalore regional edge</title><circle class="node edge" cx="390" cy="165" r="12"/><text class="n-label" x="408" y="162">Bangalore Edge</text><text class="n-meta" x="408" y="177">port 5001</text></g><g><title>Mumbai regional edge</title><circle class="node edge" cx="570" cy="235" r="12"/><text class="n-label" x="590" y="262">Mumbai Edge</text><text class="n-meta" x="590" y="277">port 5003</text></g><g><circle class="node client" cx="120" cy="350" r="9"/><text class="n-label" x="86" y="376">Jaipur</text></g><g><circle class="node client" cx="390" cy="350" r="9"/><text class="n-label" x="362" y="376">Hyderabad</text></g><g><circle class="node client" cx="660" cy="350" r="9"/><text class="n-label" x="632" y="376">Chennai</text></g></svg><div class="legend"><i style="background:var(--ok)"></i>Cache hit <i style="background:var(--warn)"></i>Cache miss <i style="background:var(--bad)"></i>Failed route · hover nodes for telemetry</div></div><div class="card control"><div class="section-head"><h2>Traffic control</h2><span>Request simulator</span></div><label class="field">Client location<select id="city">{% for city in cities %}<option>{{city}}</option>{% endfor %}</select></label><label class="field">Requested resource<select id="file">{% for file in files %}<option value="{{file}}">/{{file}}</option>{% endfor %}</select></label><button class="btn" onclick="send()">Dispatch request</button><button class="btn secondary" onclick="generate()">Generate 100 requests</button><div class="feed" id="feed">[system] NOC telemetry initialized.</div></div></section><section id="analytics" class="section"><div class="section-head"><h2>Performance analytics</h2><span>Real request telemetry</span></div><div class="grid12 charts"><div class="card wide"><canvas id="trafficChart"></canvas></div><div class="card"><canvas id="efficiencyChart"></canvas></div><div class="card"><canvas id="utilizationChart"></canvas></div><div class="card wide"><canvas id="latencyChart"></canvas></div><div class="card wide"><canvas id="originChart"></canvas></div></div></section><section id="cache" class="section"><div class="section-head"><h2>Cache inspector</h2><span>Asset residency by edge</span></div><div class="grid12 cache" id="cacheCards"></div></section><section id="health" class="section"><div class="section-head"><h2>Regional health</h2><span id="uptime">System uptime —</span></div><div class="card health" id="healthRows"></div></section><section id="requests" class="section"><div class="section-head"><h2>Request history</h2><div class="tools"><button class="action" onclick="exportData('csv')">Export CSV</button><button class="action" onclick="exportData('json')">Export JSON</button></div></div><div class="card"><div class="tools" style="margin-bottom:12px"><input id="query" oninput="renderTable()" placeholder="Search requests"><select id="filter" onchange="renderTable()"><option value="">All statuses</option><option>HIT</option><option>MISS</option></select></div><div class="table-wrap"><table><thead><tr><th>Timestamp</th><th>Client</th><th>Asset</th><th>Edge</th><th>Status</th><th>RTT</th><th></th></tr></thead><tbody id="table"></tbody></table></div></div></section><section id="settings" class="section"><div class="card"><h2>Environment settings</h2><p style="color:var(--muted)">The simulator runs locally with real HTTP sockets. Use Health controls to simulate edge outages and validate automatic rerouting.</p></div></section></main></div><script>
let rows=[],charts={};const pts={"Delhi Edge":[210,235],"Bangalore Edge":[390,165],"Mumbai Edge":[570,235]},clients={"Jaipur":[120,350],"Hyderabad":[390,350],"Chennai":[660,350],"Delhi":[210,235],"Bangalore":[390,165],"Mumbai":[570,235]};const $=id=>document.getElementById(id);const human=n=>n>1024?`${(n/1024).toFixed(1)} KB`:`${n} B`;const api=async(u,o)=>{let r=await fetch(u,o),d=await r.json();if(!r.ok)throw Error(d.message||'Request failed');return d};function feed(s){$('feed').innerHTML+=`<br>${s}`;$('feed').scrollTop=99999}function spark(id,values){let a=values.length?values:[0],max=Math.max(...a,1),w=100,h=24,p=a.map((v,i)=>`${i*(w/Math.max(a.length-1,1))},${h-(v/max)*18-3}`).join(' ');$(id).setAttribute('viewBox','0 0 100 24');$(id).innerHTML=`<polyline points="${p}" fill="none" stroke="#7C83FF" stroke-width="1.7"/>`}function trend(id,v,invert=false){let e=$(id);if(v==null){e.textContent='No baseline';return}let good=invert?v<=0:v>=0;e.innerHTML=`<b style="color:${good?'#4CAF50':'#E25A5A'}">${v>=0?'↑':'↓'} ${Math.abs(v).toFixed(1)}%</b> vs previous window`}function draw(r){let g=$('paths');g.replaceChildren();let a=clients[r.client_city],b=pts[r.edge];if(!a||!b)return;let line=(x,y,c)=>{let e=document.createElementNS('http://www.w3.org/2000/svg','line');e.setAttribute('x1',x[0]);e.setAttribute('y1',x[1]);e.setAttribute('x2',y[0]);e.setAttribute('y2',y[1]);e.setAttribute('class','route '+c);g.appendChild(e)};line(a,b,r.cache_status==='HIT'?'':'miss');if(r.cache_status==='MISS')line(b,[390,80],'miss');$('route-note').textContent=`${r.client_city} → ${r.edge} · ${r.cache_status} · ${r.latency_ms} ms`}async function send(){try{let city=$('city').value,file=$('file').value,r=await api('/api/simulate',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({city,path:file})});draw({client_city:city,edge:r.edge,cache_status:r.cache_status,latency_ms:r.total_latency_ms});feed(`[route] ${city} → ${r.edge} · ${r.cache_status} · ${r.total_latency_ms} ms`);refresh()}catch(e){feed(`<span style="color:#E25A5A">[failed] ${e.message}</span>`)}}async function generate(){feed('[traffic] generating 100 requests…');let r=await api('/api/traffic/generate',{method:'POST'});feed(`[traffic] ${r.generated} requests completed`);refresh()}async function toggle(id,on){await api('/api/edges/'+id+'/enabled',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({enabled:on})});feed(`[health] ${id.toUpperCase()} ${on?'restored':'taken offline'} — routes recalculated`);refresh()}function chart(id,type,labels,data,title,color){if(charts[id])charts[id].destroy();charts[id]=new Chart($(id),{type,data:{labels,datasets:[{label:title,data,borderColor:color,backgroundColor:type==='doughnut'?['#7C83FF','#303849']:`${color}28`,borderWidth:2,fill:type==='line',tension:.38,pointRadius:type==='line'?2:0}]},options:{plugins:{legend:{labels:{color:'#9AA4B2',boxWidth:10}},title:{display:true,text:title,color:'#F5F7FA',align:'start',font:{size:13,weight:'500'}}},scales:type==='doughnut'?{}:{x:{grid:{display:false},ticks:{color:'#9AA4B2'}},y:{grid:{color:'rgba(255,255,255,.06)'},ticks:{color:'#9AA4B2'},beginAtZero:true}}}})}function renderTable(){let q=$('query').value.toLowerCase(),f=$('filter').value;$('table').innerHTML=rows.filter(r=>(!q||`${r.client_city} ${r.file} ${r.edge}`.toLowerCase().includes(q))&&(!f||r.cache_status===f)).map((r,i)=>`<tr><td>${r.timestamp}</td><td>${r.client_city}</td><td>${r.file}</td><td>${r.edge}</td><td><span class="badge ${r.cache_status==='HIT'?'hit':'miss'}">${r.cache_status}</span></td><td>${r.latency_ms} ms</td><td><button class="action" onclick="replay(${i})">Replay</button></td></tr>`).join('')||'<tr><td colspan="7" style="color:#9AA4B2">No requests match these filters.</td></tr>'}function replay(i){let r=rows[i];$('city').value=r.client_city;$('file').value=r.file;send()}function exportData(kind){let out=kind==='json'?JSON.stringify(rows,null,2):['timestamp,city,file,edge,status,latency',...rows.map(r=>`${r.timestamp},${r.client_city},${r.file},${r.edge},${r.cache_status},${r.latency_ms}`)].join('\n'),a=document.createElement('a');a.href=URL.createObjectURL(new Blob([out],{type:'text/'+kind}));a.download='edgewatch-requests.'+kind;a.click();URL.revokeObjectURL(a.href)}async function refresh(){try{let [h,c,s,his]=await Promise.all([api('/api/health'),api('/api/cache'),api('/api/analytics'),api('/api/history')]);rows=his.requests;$('total').textContent=s.total_requests;$('rate').textContent=s.cache_hit_rate+'%';$('latency').textContent=s.average_latency_ms+' ms';$('offload').textContent=s.cache_hit_rate+'%';$('active').textContent=h.edges.filter(e=>e.status==='healthy').length+'/3';$('traffic').textContent=human(s.bandwidth_saved_bytes||0);$('updated').textContent='Updated '+new Date().toLocaleTimeString();$('uptime').textContent='System uptime '+Math.floor(h.uptime_seconds/60)+'m';let chrono=[...rows].reverse(),cut=Math.floor(chrono.length/2),old=chrono.slice(0,cut),recent=chrono.slice(cut),avg=x=>x.length?x.reduce((a,b)=>a+b.latency_ms,0)/x.length:0,rate=x=>x.length?x.filter(y=>y.cache_status==='HIT').length/x.length*100:0;trend('trend-total',old.length?((recent.length-old.length)/old.length)*100:null);trend('trend-rate',old.length?rate(recent)-rate(old):null);trend('trend-latency',old.length?((avg(recent)-avg(old))/Math.max(avg(old),1))*100:null,true);spark('spark-total',s.requests_over_time.values);spark('spark-rate',chrono.map((x,i)=>rate(chrono.slice(0,i+1))));spark('spark-latency',chrono.map((x,i)=>avg(chrono.slice(0,i+1))));spark('spark-offload',chrono.map((x,i)=>rate(chrono.slice(0,i+1))));spark('spark-active',chrono.map(()=>h.edges.filter(e=>e.status==='healthy').length));spark('spark-traffic',chrono.map((x,i)=>chrono.slice(0,i+1).filter(y=>y.cache_status==='HIT').length));chart('trafficChart','line',s.requests_over_time.labels,s.requests_over_time.values,'Traffic over time','#7C83FF');chart('efficiencyChart','doughnut',['Hit','Miss'],[s.cache_hit_rate,100-s.cache_hit_rate],'Cache efficiency','#7C83FF');chart('utilizationChart','bar',Object.keys(s.requests_per_edge),Object.values(s.requests_per_edge),'Edge utilization','#9A8CFF');chart('latencyChart','line',chrono.map((_,i)=>i+1),chrono.map(r=>r.latency_ms),'Latency distribution','#F4B942');chart('originChart','line',chrono.map((_,i)=>i+1),chrono.map((_,i)=>100-rate(chrono.slice(0,i+1))),'Origin load reduction','#4CAF50');$('healthRows').innerHTML=h.edges.map(e=>`<div class="health-row"><div><b>${e.name}</b><div style="color:#9AA4B2;font-size:11px">Port ${e.port} · ${e.requests_served} requests served</div></div><div><span class="${e.status}">● ${e.status}</span><div style="color:#9AA4B2;font-size:11px">${e.availability}% availability</div></div><div class="hide-mobile">${e.response_time_ms??'—'} ms<div style="color:#9AA4B2;font-size:11px">Response</div></div><div class="hide-mobile">CPU ${e.cpu_percent}%<div class="bar"><i style="width:${e.cpu_percent}%"></i></div></div><div class="hide-mobile">RAM ${e.memory_percent}%<div class="bar ${e.memory_percent>70?'warn':''}"><i style="width:${e.memory_percent}%"></i></div></div><div class="hide-mobile">${e.cache_entries} assets<div style="color:#9AA4B2;font-size:11px">Cached</div></div><button class="action ${e.enabled?'danger':''}" onclick="toggle('${e.id}',${!e.enabled})">${e.enabled?'Simulate failure':'Restore node'}</button></div>`).join('');$('cacheCards').innerHTML=Object.values(c.edges).map(e=>`<div class="card"><div class="section-head"><h2>${e.name}</h2><span>${e.entry_count} assets</span></div><div style="color:#9AA4B2">${human(e.size_bytes)} / 20 KB memory</div><div class="bar" style="margin:10px 0 8px"><i style="width:${Math.min(100,e.size_bytes/200)}%"></i></div>${e.entries.length?e.entries.map(x=>`<div class="file">▧ ${x.filename}<span>TTL ${x.ttl_remaining_seconds}s</span></div>`).join(''):'<div class="file" style="color:#9AA4B2">No cached assets</div>'}</div>`).join('');renderTable()}catch(e){feed(`<span style="color:#E25A5A">[monitor] ${e.message}</span>`)}}refresh();setInterval(refresh,3000);
</script></body></html>"""
